### Step 1: Define the Game Board and Pieces

We'll define an 8x8 board and initialize it with the pieces in their starting positions.

```python
import numpy as np

def initialize_board():
    board = np.zeros((8, 8), dtype=int)
    # Place black pieces (1) and white pieces (-1)
    for i in range(3):
        for j in range(0, 8, 2):
            board[i][j] = 1
    for i in range(5, 8):
        for j in range(0, 8, 2):
            board[i][j] = -1
    return board

def print_board(board):
    for row in board:
        print(' '.join(f'{cell:2d}' if cell != 0 else '  ' for cell in row))
```

### Step 2: Define Piece Movement and Capturing Rules

We'll implement the rules for moving pieces, capturing, and kinging.

```python
def is_valid_move(board, start, end):
    piece = board[start[0], start[1]]
    if board[end[0], end[1]] != 0:
        return False
    row_diff = end[0] - start[0]
    col_diff = end[1] - start[1]
    if abs(row_diff) not in [1, 2] or abs(col_diff) != 1:
        return False
    if abs(row_diff) == 2 and board[(start[0] + end[0]) // 2][(start[1] + end[1]) // 2] == 0:
        return False
    if piece == 1 and end[0] >= 7 or piece == -1 and end[0] <= 0:
        return True
    return True

def apply_move(board, start, end):
    board[end[0], end[1]] = board[start[0], start[1]]
    board[start[0], start[1]] = 0
    if abs(end[0] - start[0]) == 2:
        mid_row = (start[0] + end[0]) // 2
        mid_col = (start[1] + end[1]) // 2
        board[mid_row, mid_col] = 0

def is_game_over(board):
    # Check if any player has no pieces left
    black_pieces = np.sum(board == 1)
    white_pieces = np.sum(board == -1)
    return black_pieces == 0 or white_pieces == 0
```

